1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
7	
8	const basePremiumOf = (item: Item): number => {
9	  if (item.type === "sword") return 100;
10	  if (item.type === "amulet") return 60;
11	  if (item.type === "staff") return 80;
12	  return 0;
13	};
14	
15	const itemPremiumOf = (item: Item): number => {
16	  const base = basePremiumOf(item);
17	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
18	};
19	
20	const quotePremium = (step: Step): number => {
21	  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremiumOf(item), 0);
22	  return Math.ceil(itemsTotal + PROCESSING_FEE);
23	};
24	
25	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => ({
26	  results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
27	});
